from dataclasses import dataclass, field
from datetime import date
from typing import Optional
from statistics import mean, stdev

@dataclass
class MetricSample:
    value: float
    sampled_at: date
    source: str   # "jira" / "helpdesk" / "manual-log" / "finance-system"

@dataclass
class BenefitMetric:
    metric_id: str
    name: str
    unit: str             # "minutes", "percent", "count/day", "dollars"
    direction: str        # "lower_is_better" | "higher_is_better"
    samples: list[MetricSample] = field(default_factory=list)
    target_post_launch: Optional[float] = None

    def baseline_mean(self) -> Optional[float]:
        if not self.samples:
            return None
        return mean(s.value for s in self.samples)

    def baseline_stdev(self) -> Optional[float]:
        if len(self.samples) < 2:
            return None
        return stdev(s.value for s in self.samples)

    def improvement_needed_pct(self) -> Optional[float]:
        if self.target_post_launch is None or not self.samples:
            return None
        b = self.baseline_mean()
        t = self.target_post_launch
        if self.direction == "lower_is_better":
            return round((b - t) / b * 100, 1) if b > 0 else None
        return round((t - b) / b * 100, 1) if b > 0 else None

@dataclass
class BenefitsBaseline:
    initiative_id: str
    initiative_name: str
    baseline_start: date
    baseline_end: date
    metrics: list[BenefitMetric] = field(default_factory=list)
    notes: str = ""

    def is_complete(self) -> bool:
        """Baseline is complete when all metrics have ≥ 4 weeks of samples."""
        if not self.metrics:
            return False
        return all(len(m.samples) >= 20 for m in self.metrics)  # ~1 sample/day for 4w

def baseline_completeness_gate(baseline: BenefitsBaseline, as_of: date) -> dict:
    """Return gate status and any metrics that are not yet complete."""
    if as_of < baseline.baseline_end:
        remaining_days = (baseline.baseline_end - as_of).days
        return {
            "gate": "pending",
            "reason": f"Baseline window ends {baseline.baseline_end} ({remaining_days} days remaining)",
            "metrics_status": [
                {"metric": m.name, "samples": len(m.samples), "complete": len(m.samples) >= 20}
                for m in baseline.metrics
            ],
        }
    incomplete = [m for m in baseline.metrics if len(m.samples) < 20]
    if incomplete:
        return {
            "gate": "blocked",
            "reason": "Insufficient samples for some metrics",
            "metrics_status": [
                {"metric": m.name, "samples": len(m.samples), "complete": False}
                for m in incomplete
            ],
        }
    return {"gate": "passed", "reason": "All metrics have ≥ 20 samples"}
